{
  "name": "@kuznai/inception-engine",
  "version": "0.4.0",
  "description": "Deploy AI agent skills from a git repo to user home directories",
  "license": "MIT",
  "author": "Damian Piątkowski",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/KuzniAI/inception-engine.git"
  },
  "homepage": "https://github.com/KuzniAI/inception-engine#readme",
  "bugs": {
    "url": "https://github.com/KuzniAI/inception-engine/issues"
  },
  "keywords": [
    "cli",
    "ai",
    "agent",
    "skills",
    "claude",
    "copilot",
    "gemini",
    "deployment",
    "npx"
  ],
  "type": "module",
  "bin": {
    "inception-engine": "dist/index.js"
  },
  "files": [
    "dist"
  ],
  "engines": {
    "node": ">=23.6.0"
  },
  "scripts": {
    "build": "tsc",
    "typecheck": "tsc --noEmit",
    "format": "biome format --write .",
    "lint": "biome lint . --max-diagnostics none",
    "dev": "node src/index.ts",
    "test": "node --test test/*.test.ts",
    "prepublishOnly": "npm run typecheck && npm run lint && npm run build"
  },
  "devDependencies": {
    "@biomejs/biome": "^2.4.8",
    "@types/node": "^25.5.0",
    "typescript": "^6.0.2"
  }
}

